import re

def parse_operation(op_str):
    op_str = op_str.strip()
    m = re.match(r'(\w+)\((.*)\)\s*$', op_str)
    if not m:
        return op_str, []
    name = m.group(1)
    inner = m.group(2).strip()
    if not inner:
        return name, []
    args = []
    i = 0
    while i < len(inner):
        while i < len(inner) and inner[i] in ', \t':
            i += 1
        if i >= len(inner):
            break
        if inner[i] == '"':
            i += 1
            j = i
            while j < len(inner) and inner[j] != '"':
                j += 1
            args.append(inner[i:j])
            i = j + 1
        else:
            j = i
            while j < len(inner) and inner[j] not in ',':
                j += 1
            args.append(inner[i:j].strip())
            i = j
    return name, args

def executeTrieOperations(operations):
    results = []
    trie = None
    for op_str in operations:
        op, args = parse_operation(op_str)
        if op == 'Trie':
            trie = Trie()
            results.append(None)
        elif op == 'insert':
            trie.insert(args[0])
            results.append(None)
        elif op == 'search':
            results.append(1 if trie.search(args[0]) else 0)
        elif op == 'startsWith':
            results.append(1 if trie.startsWith(args[0]) else 0)
    return results

def prepare(test_case_input):
    return (test_case_input['operations'],)

